{
  "name": "PCCC & AI Legal Advisor",
  "description": "Hệ thống chatbot thông minh tư vấn pháp luật về Phòng cháy chữa cháy và kiến thức AI tùy chỉnh."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
}

export interface KnowledgeItem {
  id: string;
  title: string;
  content: string;
  type: 'PCCC' | 'AI' | 'General';
}

export interface AppState {
  messages: Message[];
  knowledgeBase: KnowledgeItem[];
  isStreaming: boolean;
  currentInput: string;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, KnowledgeItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
Bạn là một trợ lý AI chuyên gia về Pháp luật Phòng cháy và Chữa cháy (PCCC) tại Việt Nam và chuyên gia về Trí tuệ nhân tạo (AI).
Nhiệm vụ của bạn:
1. Tư vấn chính xác các quy định pháp luật về PCCC (Luật PCCC, các Nghị định, Thông tư liên quan).
2. Giải đáp kiến thức về AI dựa trên tài liệu người dùng cung cấp.
3. Luôn trả lời một cách lịch sự, chuyên nghiệp và dễ hiểu cho người dân.
4. Nếu câu hỏi nằm ngoài phạm vi PCCC và kiến thức AI được cung cấp, hãy nhắc nhở người dùng tập trung vào các chủ đề này.
5. Khi trích dẫn luật, hãy cố gắng nêu rõ số hiệu văn bản nếu có thể.
`;

export async function* sendMessageStream(
  messages: Message[],
  knowledgeBase: KnowledgeItem[]
) {
  const context = knowledgeBase.map(item => `[${item.type}] ${item.title}: ${item.content}`).join('\n\n');

  const history = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userMessage = history.pop()?.parts[0].text || "";

  const prompt = `
Dưới đây là kiến thức bổ sung (Context):
${context}

Dựa trên kiến thức trên và kiến thức chuyên môn của bạn, hãy trả lời câu hỏi sau của người dùng:
${userMessage}
  `;

  try {
    const stream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.95,
      },
    });

    for await (const chunk of stream) {
      yield (chunk as GenerateContentResponse).text || "";
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Xin lỗi, đã có lỗi xảy ra trong quá trình xử lý. Vui lòng thử lại sau.";
  }
}

import React, { useState } from 'react';
import { KnowledgeItem } from '../types';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [type, setType] = useState<'PCCC' | 'AI' | 'General'>('PCCC');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !content) return;
    onAdd({
      id: Date.now().toString(),
      title,
      content,
      type
    });
    setTitle('');
    setContent('');
  };

  return (
    <div className="flex flex-col h-full overflow-hidden border-r border-gray-200 bg-white">
      <div className="p-4 border-b border-gray-200 bg-gray-50 flex justify-between items-center">
        <h2 className="font-bold text-gray-700 flex items-center gap-2">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-blue-600" viewBox="0 0 20 20" fill="currentColor">
            <path d="M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10.392A7.968 7.968 0 015.5 14c1.255 0 2.443.29 3.5.804v-10.392zm2 0V15.196a7.968 7.968 0 013.5-.804c1.255 0 2.443.29 3.5.804V4.804A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804z" />
          </svg>
          Kho Kiến Thức
        </h2>
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className="text-xs bg-blue-600 text-white px-3 py-1 rounded-full hover:bg-blue-700 transition-colors"
        >
          {isOpen ? 'Đóng' : '+ Thêm'}
        </button>
      </div>

      {isOpen && (
        <form onSubmit={handleSubmit} className="p-4 border-b border-gray-200 bg-blue-50 space-y-3">
          <input 
            type="text" 
            placeholder="Tiêu đề kiến thức..." 
            className="w-full p-2 text-sm border border-blue-200 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <textarea 
            placeholder="Nội dung chi tiết..." 
            className="w-full p-2 text-sm border border-blue-200 rounded h-24 focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={content}
            onChange={(e) => setContent(e.target.value)}
          />
          <div className="flex justify-between items-center">
            <select 
              className="text-sm border border-blue-200 rounded p-1 bg-white"
              value={type}
              onChange={(e) => setType(e.target.value as any)}
            >
              <option value="PCCC">PCCC</option>
              <option value="AI">AI</option>
              <option value="General">Chung</option>
            </select>
            <button type="submit" className="bg-blue-600 text-white px-4 py-1 rounded text-sm hover:bg-blue-700">Lưu</button>
          </div>
        </form>
      )}

      <div className="flex-1 overflow-y-auto p-4 space-y-3">
        {knowledgeBase.length === 0 ? (
          <p className="text-gray-400 text-center text-sm italic mt-10">Chưa có kiến thức tùy chỉnh nào được tải lên.</p>
        ) : (
          knowledgeBase.map((item) => (
            <div key={item.id} className="p-3 rounded-lg border border-gray-100 bg-white hover:shadow-sm transition-shadow relative group">
              <div className="flex items-center gap-2 mb-1">
                <span className={`text-[10px] font-bold uppercase px-1.5 py-0.5 rounded ${
                  item.type === 'PCCC' ? 'bg-red-100 text-red-700' : 
                  item.type === 'AI' ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-700'
                }`}>
                  {item.type}
                </span>
                <h3 className="font-semibold text-sm text-gray-800 line-clamp-1">{item.title}</h3>
              </div>
              <p className="text-xs text-gray-600 line-clamp-2">{item.content}</p>
              <button 
                onClick={() => onDelete(item.id)}
                className="absolute top-2 right-2 text-gray-400 opacity-0 group-hover:opacity-100 hover:text-red-500 transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default KnowledgeManager;

import React, { useState, useRef, useEffect } from 'react';
import { Message, KnowledgeItem } from './types';
import { sendMessageStream } from './services/geminiService';
import KnowledgeManager from './components/KnowledgeManager';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: 'Xin chào! Tôi là Trợ lý AI chuyên gia về Pháp luật PCCC và Công nghệ AI. Tôi có thể giúp gì cho bạn hôm nay?',
      timestamp: new Date()
    }
  ]);
  const [knowledgeBase, setKnowledgeBase] = useState<KnowledgeItem[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const userMsg: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput('');
    setIsStreaming(true);

    let assistantMsgContent = '';
    const assistantMsg: Message = {
      role: 'model',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMsg]);

    try {
      const stream = sendMessageStream(newMessages, knowledgeBase);
      for await (const chunk of stream) {
        assistantMsgContent += chunk;
        setMessages(prev => {
          const last = prev[prev.length - 1];
          return [...prev.slice(0, -1), { ...last, content: assistantMsgContent }];
        });
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsStreaming(false);
    }
  };

  const addKnowledge = (item: KnowledgeItem) => {
    setKnowledgeBase(prev => [...prev, item]);
  };

  const deleteKnowledge = (id: string) => {
    setKnowledgeBase(prev => prev.filter(item => item.id !== id));
  };

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden">
      {/* Sidebar for Knowledge Management */}
      <aside className="hidden md:block w-80 lg:w-96 flex-shrink-0 shadow-lg z-20">
        <KnowledgeManager 
          onAdd={addKnowledge} 
          knowledgeBase={knowledgeBase} 
          onDelete={deleteKnowledge} 
        />
      </aside>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-white shadow-inner">
        {/* Header */}
        <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-red-600 rounded-full flex items-center justify-center text-white shadow-md">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 18.657A8 8 0 016.343 7.343S7 9 9 10c0-2 .5-5 2.986-7C14 5 16.09 5.777 17.656 7.343A7.99 7.99 0 0120 13a7.98 7.98 0 01-2.343 5.657z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.879 16.121A3 3 0 1012.015 11L11 14H9c0 .768.293 1.536.879 2.121z" />
              </svg>
            </div>
            <div>
              <h1 className="font-bold text-gray-800 text-lg">PCCC & AI Advisor</h1>
              <p className="text-xs text-green-500 flex items-center gap-1">
                <span className="w-2 h-2 bg-green-500 rounded-full"></span> Trực tuyến
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <span className="hidden sm:inline-block text-xs text-gray-400 bg-gray-100 px-2 py-1 rounded">Sử dụng Gemini 3 Flash</span>
            <button className="md:hidden p-2 text-gray-600 hover:bg-gray-100 rounded-full">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" />
              </svg>
            </button>
          </div>
        </header>

        {/* Chat Messages */}
        <section className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6">
          <div className="max-w-3xl mx-auto space-y-6">
            {messages.map((msg, idx) => (
              <div 
                key={idx} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[85%] md:max-w-[75%] rounded-2xl p-4 ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white shadow-blue-200' 
                    : 'bg-white border border-gray-100 shadow-sm text-gray-800'
                }`}>
                  <div className="whitespace-pre-wrap leading-relaxed">
                    {msg.content || (isStreaming && idx === messages.length - 1 ? (
                      <div className="flex space-x-1 py-2">
                        <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></div>
                        <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                        <div className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce delay-150"></div>
                      </div>
                    ) : null)}
                  </div>
                  <div className={`mt-2 text-[10px] opacity-70 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>
        </section>

        {/* Input Area */}
        <footer className="p-4 border-t border-gray-200 bg-gray-50 sticky bottom-0">
          <div className="max-w-3xl mx-auto">
            <div className="relative flex items-end gap-2 bg-white border border-gray-200 rounded-2xl p-2 shadow-sm focus-within:ring-2 focus-within:ring-blue-500 focus-within:border-transparent transition-all">
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
                placeholder="Hỏi về luật PCCC hoặc kiến thức AI..."
                rows={1}
                className="flex-1 resize-none border-none focus:ring-0 text-sm md:text-base p-2 bg-transparent max-h-32"
                style={{ height: 'auto' }}
              />
              <button
                onClick={handleSend}
                disabled={!input.trim() || isStreaming}
                className={`p-2.5 rounded-xl transition-all ${
                  !input.trim() || isStreaming 
                    ? 'bg-gray-100 text-gray-400 cursor-not-allowed' 
                    : 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg shadow-blue-100'
                }`}
              >
                {isStreaming ? (
                  <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 transform rotate-90" viewBox="0 0 20 20" fill="currentColor">
                    <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
                  </svg>
                )}
              </button>
            </div>
            <p className="mt-2 text-center text-[10px] text-gray-400">
              Trợ lý AI có thể cung cấp thông tin tham khảo. Vui lòng đối chiếu với văn bản pháp luật chính thức.
            </p>
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

export interface Message {
  role: 'user' | 'model';
  content: string;
  timestamp: Date;
}

export interface KnowledgeItem {
  id: string;
  title: string;
  content: string; // Trích xuất văn bản (dành cho DOCX/Text)
  fileData?: string; // Base64 (dành cho PDF)
  mimeType: string;
  size: number;
}

export interface AppState {
  messages: Message[];
  knowledgeBase: KnowledgeItem[];
  isStreaming: boolean;
  currentInput: string;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, KnowledgeItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
Bạn là một trợ lý AI chuyên gia phân tích tài liệu. 
NHIỆM VỤ CHIẾN LƯỢC:
1. Bạn CHỈ ĐƯỢC PHÉP trả lời dựa trên các tài liệu (PDF, văn bản) mà người dùng đã cung cấp trong Context.
2. Nếu câu hỏi của người dùng không thể tìm thấy câu trả lời trong các tài liệu đã tải lên, hãy lịch sự trả lời: "Rất tiếc, thông tin này không nằm trong kho tài liệu tôi được cung cấp. Vui lòng bổ sung thêm tài liệu hoặc hỏi vấn đề liên quan."
3. Tuyệt đối không tự bịa đặt hoặc sử dụng kiến thức bên ngoài nếu nó mâu thuẫn hoặc không có trong tài liệu.
4. Khi trả lời, hãy trích dẫn tên tài liệu cụ thể nếu có thể để tăng độ tin cậy.
5. Luôn giữ phong thái chuyên nghiệp, chính xác và khách quan.
`;

export async function* sendMessageStream(
  messages: Message[],
  knowledgeBase: KnowledgeItem[]
) {
  // Chuẩn bị các phần (parts) cho Gemini
  const parts: any[] = [];

  // 1. Thêm các tài liệu PDF dưới dạng inlineData
  knowledgeBase.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: item.mimeType
        }
      });
    }
  });

  // 2. Gom tất cả văn bản trích xuất (từ DOCX hoặc PDF text) vào một khối context
  const textContext = knowledgeBase
    .filter(item => item.content && item.mimeType !== 'application/pdf')
    .map(item => `[TÀI LIỆU: ${item.title}]\n${item.content}`)
    .join('\n\n---\n\n');

  const history = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = history.pop()?.parts[0].text || "";

  // Tạo prompt cuối cùng
  const finalPrompt = `
DƯỚI ĐÂY LÀ KHO KIẾN THỨC BỔ SUNG (VĂN BẢN TRÍCH XUẤT):
${textContext || "Không có văn bản trích xuất bổ sung."}

CÂU HỎI CỦA NGƯỜI DÙNG:
${userQuery}

HÃY PHÂN TÍCH CẢ FILE PDF ĐÍNH KÈM VÀ VĂN BẢN TRÊN ĐỂ TRẢ LỜI.
  `;

  try {
    const stream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [...parts, { text: finalPrompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Thấp để đảm bảo tính chính xác cao, bám sát tài liệu
        topP: 0.95,
      },
    });

    for await (const chunk of stream) {
      yield (chunk as GenerateContentResponse).text || "";
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Xin lỗi, tôi gặp khó khăn khi đọc các tài liệu này. Vui lòng kiểm tra lại định dạng file.";
  }
}

import React, { useState, useCallback } from 'react';
import { KnowledgeItem } from '../types';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);

  const processFile = async (file: File) => {
    setIsUploading(true);
    try {
      const reader = new FileReader();

      if (file.type === 'application/pdf') {
        // Xử lý PDF: Chuyển sang Base64 để gửi trực tiếp cho Gemini
        const base64 = await new Promise<string>((resolve) => {
          const r = new FileReader();
          r.onload = () => {
            const result = r.result as string;
            resolve(result.split(',')[1]);
          };
          r.readAsDataURL(file);
        });

        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: '', // Gemini sẽ tự đọc nội dung từ fileData
          fileData: base64,
          mimeType: file.type,
          size: file.size
        });
      } else if (file.name.endsWith('.docx')) {
        // Xử lý DOCX bằng mammoth
        const arrayBuffer = await file.arrayBuffer();
        // @ts-ignore (mammoth is loaded via CDN)
        const result = await window.mammoth.extractRawText({ arrayBuffer });

        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: result.value,
          mimeType: file.type || 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
          size: file.size
        });
      } else if (file.type === 'text/plain') {
        const text = await file.text();
        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: text,
          mimeType: file.type,
          size: file.size
        });
      } else {
        alert('Định dạng file không được hỗ trợ. Vui lòng sử dụng PDF, DOCX hoặc TXT.');
      }
    } catch (error) {
      console.error("Lỗi xử lý file:", error);
      alert("Không thể đọc file này.");
