import React, { useState, useRef, useEffect } from 'react';
import { Message, KnowledgeItem } from './types';
import { sendMessageStream } from './services/geminiService';
import KnowledgeManager from './components/KnowledgeManager';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: 'Chào mừng bạn! Hãy tải lên các tài liệu pháp luật về PCCC hoặc tài liệu AI của bạn. Tôi sẽ học và giải đáp thắc mắc của bạn DỰA TRÊN CHÍNH CÁC TÀI LIỆU ĐÓ.',
      timestamp: new Date()
    }
  ]);
  const [knowledgeBase, setKnowledgeBase] = useState<KnowledgeItem[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    if (knowledgeBase.length === 0) {
      setMessages(prev => [...prev, {
        role: 'model',
        content: 'Vui lòng tải lên ít nhất một tài liệu để tôi có cơ sở dữ liệu trả lời bạn.',
        timestamp: new Date()
      }]);
      return;
    }

    const userMsg: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput('');
    setIsStreaming(true);

    let assistantMsgContent = '';
    const assistantMsg: Message = {
      role: 'model',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMsg]);

    try {
      const stream = sendMessageStream(newMessages, knowledgeBase);
      for await (const chunk of stream) {
        assistantMsgContent += chunk;
        setMessages(prev => {
          const last = prev[prev.length - 1];
          return [...prev.slice(0, -1), { ...last, content: assistantMsgContent }];
        });
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsStreaming(false);
    }
  };

  const addKnowledge = (item: KnowledgeItem) => {
    setKnowledgeBase(prev => [...prev, item]);
  };

  const deleteKnowledge = (id: string) => {
    setKnowledgeBase(prev => prev.filter(item => item.id !== id));
  };

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden">
      {/* Sidebar for Knowledge Management */}
      <aside className="hidden md:block w-80 lg:w-96 flex-shrink-0 z-20">
        <KnowledgeManager 
          onAdd={addKnowledge} 
          knowledgeBase={knowledgeBase} 
          onDelete={deleteKnowledge} 
        />
      </aside>

      {/* Main Chat Area */}
      <main className="flex-1 flex flex-col min-w-0 bg-white shadow-inner relative">
        {/* Header */}
        <header className="bg-white/80 backdrop-blur-md border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-100 rotate-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <div>
              <h1 className="font-bold text-gray-800 text-lg">AI Document Specialist</h1>
              <p className="text-[10px] text-gray-500 flex items-center gap-1 font-medium">
                <span className="flex h-2 w-2 rounded-full bg-green-500 animate-pulse"></span> 
                {knowledgeBase.length} TÀI LIỆU TRONG KHO
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <div className="hidden sm:flex flex-col items-end">
               <span className="text-[10px] font-bold text-blue-600 tracking-wider">GEMINI 3 PRO</span>
               <span className="text-[9px] text-gray-400">Context Window: 2M+ tokens</span>
            </div>
          </div>
        </header>

        {/* Chat Messages */}
        <section className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] bg-opacity-5">
          <div className="max-w-3xl mx-auto space-y-6">
            {messages.map((msg, idx) => (
              <div 
                key={idx} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[85%] md:max-w-[80%] rounded-2xl p-5 shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-tr-none' 
                    : 'bg-white border border-gray-100 text-gray-800 rounded-tl-none'
                }`}>
                  <div className="prose prose-sm max-w-none whitespace-pre-wrap leading-relaxed">
                    {msg.content || (isStreaming && idx === messages.length - 1 ? (
                      <div className="flex items-center space-x-2 py-2">
                         <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce"></div>
                         <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                         <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                      </div>
                    ) : null)}
                  </div>
                  <div className={`mt-3 text-[9px] font-medium uppercase tracking-widest opacity-50 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {msg.role === 'user' ? 'Bạn' : 'Hệ thống'}
                  </div>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>
        </section>

        {/* Input Area */}
        <footer className="p-6 border-t border-gray-100 bg-white shadow-[0_-4px_20px_rgba(0,0,0,0.03)]">
          <div className="max-w-3xl mx-auto">
            <div className={`relative flex items-end gap-3 bg-gray-50 border border-gray-200 rounded-2xl p-3 focus-within:ring-2 focus-within:ring-blue-500/20 focus-within:border-blue-500 transition-all ${isStreaming ? 'opacity-70' : ''}`}>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
                placeholder={knowledgeBase.length === 0 ? "Hãy tải tài liệu lên trước..." : "Phân tích nội dung tài liệu..."}
                rows={1}
                className="flex-1 resize-none border-none focus:ring-0 text-sm md:text-base p-2 bg-transparent max-h-48 scrollbar-hide"
                style={{ height: 'auto' }}
              />
              <button
                onClick={handleSend}
                disabled={!input.trim() || isStreaming}
                className={`p-3 rounded-xl transition-all shadow-md ${
                  !input.trim() || isStreaming 
                    ? 'bg-gray-200 text-gray-400 cursor-not-allowed' 
                    : 'bg-blue-600 text-white hover:bg-blue-700 hover:shadow-blue-200 active:scale-95'
                }`}
              >
                {isStreaming ? (
                  <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
                  </svg>
