import React, { useState, useCallback } from 'react';
import { KnowledgeItem } from '../types';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);

  // Giới hạn 20MB cho mỗi file đơn lẻ
  const MAX_SINGLE_FILE_SIZE = 20 * 1024 * 1024; 
  // Giới hạn tổng dung lượng thô (vì base64 sẽ tăng kích thước lên ~33%, 35MB thô ~ 47MB base64)
  const MAX_TOTAL_SIZE = 35 * 1024 * 1024; 

  const processFile = async (file: File) => {
    // Kiểm tra dung lượng file đơn lẻ
    if (file.size > MAX_SINGLE_FILE_SIZE) {
      alert(`File "${file.name}" quá lớn (${formatSize(file.size)}). Vui lòng tải lên file dưới 20MB.`);
      return;
    }

    // Kiểm tra tổng dung lượng kho kiến thức
    const currentTotalSize = knowledgeBase.reduce((acc, item) => acc + item.size, 0);
    if (currentTotalSize + file.size > MAX_TOTAL_SIZE) {
      alert(`Tổng dung lượng tài liệu vượt quá giới hạn cho phép (35MB thô). Vui lòng xóa bớt tài liệu cũ trước khi tải thêm.`);
      return;
    }

    setIsUploading(true);
    try {
      if (file.type === 'application/pdf') {
        // Xử lý PDF: Chuyển sang Base64 để gửi trực tiếp cho Gemini
        const base64 = await new Promise<string>((resolve, reject) => {
          const r = new FileReader();
          r.onload = () => {
            const result = r.result as string;
            resolve(result.split(',')[1]);
          };
          r.onerror = reject;
          r.readAsDataURL(file);
        });

        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: '', 
          fileData: base64,
          mimeType: file.type,
          size: file.size
        });
      } else if (file.name.endsWith('.docx') || file.name.endsWith('.doc')) {
        // Xử lý DOCX/DOC bằng mammoth (Lưu ý: mammoth hỗ trợ tốt nhất .docx)
        const arrayBuffer = await file.arrayBuffer();
        // @ts-ignore (mammoth is loaded via CDN)
        const result = await window.mammoth.extractRawText({ arrayBuffer });

        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: result.value,
          mimeType: 'text/plain', // Lưu dưới dạng text để nhẹ hơn
          size: file.size
        });
      } else if (file.type === 'text/plain' || file.name.endsWith('.txt')) {
        const text = await file.text();
        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: text,
          mimeType: 'text/plain',
          size: file.size
        });
      } else {
        alert('Định dạng file không được hỗ trợ. Vui lòng sử dụng PDF, DOCX hoặc TXT.');
      }
    } catch (error) {
      console.error("Lỗi xử lý file:", error);
      alert("Không thể đọc file này. Vui lòng kiểm tra lại định dạng hoặc file có bị khóa mật khẩu không.");
    } finally {
      setIsUploading(false);
    }
  };

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
      // Reset input để có thể chọn lại cùng 1 file nếu cần
      e.target.value = '';
    }
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col h-full overflow-hidden border-r border-gray-200 bg-white shadow-xl">
      <div className="p-5 border-b border-gray-100 bg-gradient-to-r from-blue-50 to-white">
        <h2 className="font-bold text-gray-800 flex items-center gap-2 text-lg">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
          </svg>
          Kho Tài Liệu Gốc
        </h2>
        <p className="text-xs text-gray-500 mt-1">AI sẽ CHỈ trả lời dựa trên các file này.</p>
      </div>

      <div className="p-4">
        <label className={`file-drop-zone block p-6 rounded-xl text-center cursor-pointer ${isUploading ? 'opacity-50 cursor-not-allowed' : ''}`}>
          <input 
            type="file" 
            className="hidden" 
            accept=".pdf,.docx,.doc,.txt" 
            onChange={onFileChange}
            disabled={isUploading}
          />
          <div className="flex flex-col items-center">
            {isUploading ? (
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mb-2"></div>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-gray-400 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
            )}
            <span className="text-sm font-medium text-gray-700">
              {isUploading ? 'Đang xử lý...' : 'Tải lên PDF, DOCX'}
            </span>
            <span className="text-[10px] text-gray-400 mt-1">Tối đa 20MB/file • Tổng 35MB</span>
          </div>
        </label>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3">
        {knowledgeBase.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-40 text-gray-400">
            <p className="text-sm italic">Chưa có tài liệu nào</p>
          </div>
        ) : (
          knowledgeBase.map((item) => (
            <div key={item.id} className="p-3 rounded-xl border border-gray-100 bg-white hover:border-blue-200 hover:shadow-md transition-all relative group">
              <div className="flex items-start gap-3">
                <div className={`p-2 rounded-lg ${
