export default KnowledgeManager;

import React, { useState } from 'react';
import { KnowledgeItem } from '../types';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState('');

  // Nâng giới hạn tải lên lên 100MB cho giao diện người dùng
  const MAX_SINGLE_FILE_SIZE = 100 * 1024 * 1024; 
  // Ngưỡng để chuyển từ gửi File sang trích xuất Text (để tránh lỗi 50MB của Gemini)
  const EXTRACTION_THRESHOLD = 15 * 1024 * 1024; 

  const extractTextFromPDF = async (arrayBuffer: ArrayBuffer): Promise<string> => {
    // @ts-ignore
    const pdf = await window.pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = '';
    for (let i = 1; i <= pdf.numPages; i++) {
      setUploadProgress(`Đang trích xuất trang ${i}/${pdf.numPages}...`);
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      // Thêm kiểm tra an toàn cho item.str
      const pageText = textContent.items
        .map((item: any) => (item.str !== undefined ? item.str : ''))
        .join(' ');
      fullText += pageText + '\n';
    }
    return fullText;
  };

  const processFile = async (file: File) => {
    // Kiểm tra file trống
    if (file.size === 0) {
      alert(`File "${file.name}" trống (0 bytes). Vui lòng chọn file có nội dung.`);
      return;
    }

    if (file.size > MAX_SINGLE_FILE_SIZE) {
      alert(`File "${file.name}" quá lớn (${formatSize(file.size)}). Vui lòng sử dụng file dưới 100MB.`);
      return;
    }

    // Kiểm tra định dạng .doc cũ (không được mammoth hỗ trợ)
    if (file.name.toLowerCase().endsWith('.doc')) {
      alert('Định dạng .doc (cũ) không được hỗ trợ. Vui lòng lưu file dưới dạng .docx hoặc .pdf để tiếp tục.');
      return;
    }

    setIsUploading(true);
    setUploadProgress('Đang khởi tạo...');

    try {
      const arrayBuffer = await file.arrayBuffer();

      // Kiểm tra buffer có dữ liệu hay không để tránh lỗi "End of data reached"
      if (!arrayBuffer || arrayBuffer.byteLength === 0) {
        throw new Error("Không thể đọc dữ liệu từ file. Dữ liệu trả về rỗng.");
      }

      const fileNameLower = file.name.toLowerCase();

      if (file.type === 'application/pdf' || fileNameLower.endsWith('.pdf')) {
        if (file.size > EXTRACTION_THRESHOLD) {
          // File lớn: Trích xuất văn bản để giảm dung lượng payload
          setUploadProgress('File lớn, đang trích xuất văn bản...');
          const text = await extractTextFromPDF(arrayBuffer);

          if (!text.trim()) {
            throw new Error("PDF không chứa văn bản có thể trích xuất (có thể là file ảnh scan).");
          }

          onAdd({
            id: Math.random().toString(36).substr(2, 9),
            title: file.name + ' (Văn bản trích xuất)',
            content: text,
            mimeType: 'text/plain',
            size: file.size
          });
        } else {
          // File nhỏ: Gửi nguyên bản PDF để giữ định dạng tốt nhất
          setUploadProgress('Đang mã hóa PDF...');
          const base64 = await new Promise<string>((resolve, reject) => {
            const r = new FileReader();
            r.onload = () => resolve((r.result as string).split(',')[1]);
            r.onerror = () => reject(new Error("Lỗi khi chuyển đổi PDF sang Base64"));
            r.readAsDataURL(file);
          });

          onAdd({
            id: Math.random().toString(36).substr(2, 9),
            title: file.name,
            content: '', 
            fileData: base64,
            mimeType: 'application/pdf',
            size: file.size
          });
        }
      } else if (fileNameLower.endsWith('.docx')) {
        setUploadProgress('Đang đọc tài liệu Word...');

        try {
          // @ts-ignore
          const result = await window.mammoth.extractRawText({ arrayBuffer });

          if (!result || result.value === undefined) {
            throw new Error("Không thể trích xuất văn bản từ file Word.");
          }

          onAdd({
            id: Math.random().toString(36).substr(2, 9),
            title: file.name,
            content: result.value,
            mimeType: 'text/plain',
            size: file.size
          });
        } catch (mErr: any) {
          console.error("Mammoth error:", mErr);
          if (mErr.message && mErr.message.includes("End of data reached")) {
            throw new Error("File Word bị hỏng hoặc không đúng định dạng .docx chuẩn (Zip).");
          }
          throw mErr;
        }
      } else if (file.type === 'text/plain' || fileNameLower.endsWith('.txt')) {
        const text = await file.text();
        onAdd({
          id: Math.random().toString(36).substr(2, 9),
          title: file.name,
          content: text,
          mimeType: 'text/plain',
          size: file.size
        });
      } else {
        alert('Định dạng file không được hỗ trợ. Vui lòng sử dụng PDF, DOCX hoặc TXT.');
      }
    } catch (error: any) {
      console.error("Lỗi xử lý file:", error);
      const errorMsg = error?.message || "";
      if (errorMsg.includes('children')) {
        alert("Lỗi cấu trúc tài liệu Word. Hãy thử mở file và lưu lại (Save As) dưới dạng .docx mới nhất.");
      } else if (errorMsg.includes('End of data reached')) {
        alert("Lỗi: File bị hỏng hoặc không chứa dữ liệu hợp lệ. Vui lòng kiểm tra lại file của bạn.");
      } else {
        alert(`Lỗi: ${errorMsg || "Không thể đọc file này. Vui lòng thử lại với định dạng PDF hoặc DOCX chuẩn."}`);
      }
    } finally {
      setIsUploading(false);
      setUploadProgress('');
    }
  };

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
      e.target.value = '';
    }
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col h-full overflow-hidden border-r border-gray-200 bg-white shadow-xl">
      <div className="p-5 border-b border-gray-100 bg-gradient-to-br from-blue-600 to-blue-800 text-white">
        <h2 className="font-bold flex items-center gap-2 text-lg">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
          </svg>
          Kho Kiến Thức AI
        </h2>
        <p className="text-[10px] opacity-80 mt-1 uppercase tracking-wider font-semibold">Tải lên tài liệu của riêng bạn</p>
      </div>

      <div className="p-4">
        <label className={`file-drop-zone block p-6 rounded-2xl text-center cursor-pointer transition-all border-dashed border-2 ${
          isUploading ? 'bg-gray-50 border-blue-300' : 'bg-white border-gray-200 hover:border-blue-400 hover:bg-blue-50'
        }`}>
          <input 
            type="file" 
            className="hidden" 
            accept=".pdf,.docx,.txt" 
            onChange={onFileChange}
            disabled={isUploading}
          />
          <div className="flex flex-col items-center">
            {isUploading ? (
              <div className="flex flex-col items-center">
                <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600 mb-3"></div>
                <span className="text-xs font-bold text-blue-600 animate-pulse">{uploadProgress}</span>
              </div>
            ) : (
              <>
                <div className="w-12 h-12 bg-blue-100 rounded-full flex items-center justify-center mb-3">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <span className="text-sm font-bold text-gray-700">Tải tài liệu mới</span>
                <span className="text-[10px] text-gray-400 mt-1">Hỗ trợ PDF, DOCX, TXT (Max 100MB)</span>
              </>
            )}
          </div>
        </label>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
        <div className="flex items-center justify-between mb-2 px-1">
          <span className="text-[10px] font-bold text-gray-400 uppercase">Danh sách tài liệu ({knowledgeBase.length})</span>
          {knowledgeBase.length > 0 && (
            <span className="text-[10px] font-mono text-gray-400">
              Tổng: {formatSize(knowledgeBase.reduce((a, b) => a + b.size, 0))}
            </span>
          )}
        </div>

        {knowledgeBase.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-gray-300 opacity-60">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z" />
            </svg>
            <p className="text-sm italic">Kho kiến thức đang trống</p>
          </div>
        ) : (
          knowledgeBase.map((item) => (
            <div key={item.id} className="group relative bg-white border border-gray-100 rounded-xl p-3 hover:shadow-lg hover:border-blue-200 transition-all">
              <div className="flex items-start gap-3">
                <div className={`shrink-0 w-10 h-10 rounded-lg flex items-center justify-center ${
                  item.mimeType === 'application/pdf' ? 'bg-red-50 text-red-500' : 
                  item.title.toLowerCase().includes('.docx') ? 'bg-blue-50 text-blue-500' : 'bg-gray-50 text-gray-500'
                }`}>
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                  </svg>
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="text-xs font-bold text-gray-800 truncate pr-6 mb-1" title={item.title}>
                    {item.title}
                  </h3>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-gray-400 bg-gray-50 px-1 rounded border border-gray-100">{formatSize(item.size)}</span>
                    <span className="text-[9px] font-bold text-green-600 flex items-center gap-0.5">
                      <span className="w-1 h-1 bg-green-500 rounded-full animate-pulse"></span> SẴN SÀNG
                    </span>
                  </div>
                </div>
              </div>
              <button 
                onClick={() => onDelete(item.id)}
                className="absolute top-2 right-2 text-gray-300 opacity-0 group-hover:opacity-100 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-lg transition-all"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          ))
        )}
      </div>

      <div className="p-4 bg-blue-50/50 text-[10px] text-blue-700/70 border-t border-blue-100 flex gap-2 italic">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
        </svg>
        <span>Lưu ý: Chỉ hỗ trợ file Word .docx (OpenXML). Các file .doc đời cũ cần được chuyển đổi sang .docx hoặc PDF trước khi tải lên.</span>
      </div>
    </div>
  );
};

export default KnowledgeManager;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, KnowledgeItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
VAI TRÒ (ROLE):
Bạn là Trợ lý ảo AI chuyên trách tư vấn về Phòng cháy chữa cháy (PCCC) và Cứu nạn cứu hộ (CNCH) của tỉnh Phú Thọ.

NGUYÊN TẮC TRẢ LỜI:
1. TRUNG THỰC: Chỉ trả lời dựa trên thông tin trong mục "DỮ LIỆU KIẾN THỨC" được cung cấp. Nếu người dân hỏi điều gì không có trong đó, hãy trả lời: "Xin lỗi, hiện tôi chưa có thông tin chính thức về vấn đề này, bạn có thể liên hệ trực tiếp cán bộ hướng dẫn kiểm tra an toàn PCCC các khu vực để được giải đáp!."
2. TRÍCH DẪN: Luôn trích dẫn nguồn cụ thể từ tài liệu (Ví dụ: "Theo điều 30 Luật PCCC và CNCH...", hoặc "Theo tài liệu [Tên tài liệu]...").
3. GIỌNG VĂN: Lịch sự, ngắn gọn, dễ hiểu, dùng từ ngữ toàn dân (tránh dùng từ quá chuyên môn khó hiểu).
4. PHẠM VI: Tập trung tối đa vào các quy định pháp luật và kiến thức kỹ thuật có trong tài liệu người dùng đã tải lên.
`;

export async function* sendMessageStream(
  messages: Message[],
  knowledgeBase: KnowledgeItem[]
) {
  const parts: any[] = [];

  // 1. Chuẩn bị các file PDF nhỏ (<15MB) dưới dạng inlineData
  knowledgeBase.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: item.mimeType
        }
      });
    }
  });

  // 2. Gom tất cả văn bản trích xuất (từ Word, TXT hoặc PDF lớn)
  const textContext = knowledgeBase
    .filter(item => item.content && (item.mimeType !== 'application/pdf' || !item.fileData))
    .map(item => `[TÀI LIỆU: ${item.title}]\n${item.content}`)
    .join('\n\n---\n\n');

  const history = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = history.pop()?.parts[0].text || "";

  // Tạo prompt cuối cùng với nhãn "DỮ LIỆU KIẾN THỨC" rõ ràng
  const finalPrompt = `
DỮ LIỆU KIẾN THỨC:
${textContext || "Không có văn bản trích xuất bổ sung. Vui lòng xem các file đính kèm."}

CÂU HỎI CỦA NGƯỜI DÂN:
${userQuery}

Lưu ý: Chỉ sử dụng DỮ LIỆU KIẾN THỨC trên và các file đính kèm để trả lời. Nếu không thấy thông tin, hãy dùng câu phản hồi mặc định đã quy định.
  `;

  try {
    const stream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [...parts, { text: finalPrompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Giảm temperature để tăng độ chính xác và trung thực
        topP: 0.95,
      },
    });

    for await (const chunk of stream) {
      yield (chunk as GenerateContentResponse).text || "";
    }
  } catch (error: any) {
    console.error("Gemini API Error:", error);
