  // 1. Chuẩn bị file PDF từ kho bổ sung của người dùng
  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: item.mimeType
        }
      });
    }
  });

  // 2. Gom kiến thức hệ thống cố định (3 file Word của bạn)
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[NGUỒN HỆ THỐNG: ${doc.title}]\n${doc.content}`)
    .join('\n\n---\n\n');

  // 3. Gom kiến thức bổ sung của người dùng
  const userTextContext = userKnowledge
    .filter(item => item.content && (item.mimeType !== 'application/pdf' || !item.fileData))
    .map(item => `[TÀI LIỆU BỔ SUNG: ${item.title}]\n${item.content}`)
    .join('\n\n---\n\n');

  const history = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = history.pop()?.parts[0].text || "";

  const finalPrompt = `
DỮ LIỆU KIẾN THỨC HỆ THỐNG (NGUỒN CHÍNH):
${systemTextContext}

DỮ LIỆU BỔ SUNG (NẾU CÓ):
${userTextContext || "Không có."}

CÂU HỎI CỦA NGƯỜI DÂN:
${userQuery}

Yêu cầu: Sử dụng nguồn hệ thống để trả lời chính xác cho người dân.
  `;

  try {
    const stream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [...parts, { text: finalPrompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
        topP: 0.95,
      },
    });

    for await (const chunk of stream) {
      yield (chunk as GenerateContentResponse).text || "";
    }
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    yield "Xin lỗi, hệ thống đang bận. Vui lòng thử lại sau.";
  }
}

import React, { useState } from 'react';
import { KnowledgeItem } from '../types';
import { SYSTEM_DOCUMENTS } from '../services/systemKnowledge';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState('');

  const MAX_SINGLE_FILE_SIZE = 100 * 1024 * 1024; 
  const EXTRACTION_THRESHOLD = 15 * 1024 * 1024; 

  const extractTextFromPDF = async (arrayBuffer: ArrayBuffer): Promise<string> => {
    // @ts-ignore
    const pdf = await window.pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = '';
    for (let i = 1; i <= pdf.numPages; i++) {
      setUploadProgress(`Đang trích xuất trang ${i}/${pdf.numPages}...`);
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const pageText = textContent.items.map((item: any) => item.str || '').join(' ');
      fullText += pageText + '\n';
    }
    return fullText;
  };

  const processFile = async (file: File) => {
    if (file.size === 0) return;
    setIsUploading(true);
    setUploadProgress('Đang xử lý...');

    try {
      const arrayBuffer = await file.arrayBuffer();
      const fileNameLower = file.name.toLowerCase();

      if (fileNameLower.endsWith('.pdf')) {
        if (file.size > EXTRACTION_THRESHOLD) {
          const text = await extractTextFromPDF(arrayBuffer);
          onAdd({ id: Math.random().toString(36).substr(2, 9), title: file.name, content: text, mimeType: 'text/plain', size: file.size });
        } else {
          const base64 = await new Promise<string>((resolve) => {
            const r = new FileReader();
            r.onload = () => resolve((r.result as string).split(',')[1]);
            r.readAsDataURL(file);
          });
          onAdd({ id: Math.random().toString(36).substr(2, 9), title: file.name, content: '', fileData: base64, mimeType: 'application/pdf', size: file.size });
        }
      } else if (fileNameLower.endsWith('.docx')) {
        // @ts-ignore
        const result = await window.mammoth.extractRawText({ arrayBuffer });
        onAdd({ id: Math.random().toString(36).substr(2, 9), title: file.name, content: result.value, mimeType: 'text/plain', size: file.size });
      }
    } catch (error) {
      console.error(error);
      alert("Lỗi khi đọc file.");
    } finally {
      setIsUploading(false);
      setUploadProgress('');
    }
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col h-full bg-white border-r border-gray-200 shadow-xl overflow-hidden">
      <div className="p-5 bg-gradient-to-br from-red-600 to-red-800 text-white shadow-md">
        <h2 className="font-bold flex items-center gap-2 text-lg">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
          </svg>
          Thư Viện PCCC Phú Thọ
        </h2>
        <p className="text-[10px] opacity-80 mt-1 uppercase tracking-widest font-bold">Nguồn dữ liệu chính thống</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
        {/* Section 1: System Documents (Fixed) */}
        <div>
          <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <span className="w-2 h-2 bg-red-500 rounded-full"></span>
            Tài liệu hệ thống ({SYSTEM_DOCUMENTS.length})
          </h3>
          <div className="space-y-2">
            {SYSTEM_DOCUMENTS.map(doc => (
              <div key={doc.id} className="bg-red-50 border border-red-100 rounded-xl p-3 flex items-center gap-3">
                <div className="w-8 h-8 bg-red-100 text-red-600 rounded flex items-center justify-center shrink-0">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M5 4a3 3 0 00-3 3v6a3 3 0 003 3h10a3 3 0 003-3V7a3 3 0 00-3-3H5zm-1 9v-1h5v2H5a1 1 0 01-1-1zm7 1h4a1 1 0 001-1v-1h-5v2zm0-4h5V8h-5v2zM9 8H4v2h5V8z" clipRule="evenodd" />
                  </svg>
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-bold text-red-900 truncate" title={doc.title}>{doc.title}</p>
                  <p className="text-[9px] text-red-600 font-medium">NGUỒN GỐC: Phú Thọ AI</p>
