        </div>

        {/* Section 2: User Documents (Dynamic) */}
        <div>
          <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-2">
            <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
            Tài liệu bổ sung ({knowledgeBase.length})
          </h3>

          <label className={`block p-4 rounded-xl text-center cursor-pointer border-2 border-dashed transition-all mb-4 ${
