import React, { useState, useRef, useEffect } from 'react';
import { Message, KnowledgeItem } from './types';
import { sendMessageStream } from './services/geminiService';
import KnowledgeManager from './components/KnowledgeManager';
import { getFullKnowledge, saveKnowledge, removeKnowledge } from './services/storageService';
import { SYSTEM_DOCUMENTS } from './services/systemKnowledge';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: 'Xin chào! Tôi là Trợ lý ảo AI chuyên trách tư vấn PCCC & CNCH tỉnh Phú Thọ.\n\nTôi đã nạp sẵn kiến thức từ:\n1. Luật PCCC số 55/2024\n2. Nghị định 105/2025/NĐ-CP\n3. Thông tư 36/2025/TT-BCA\n\nBạn cần tôi tư vấn quy định nào trong các văn bản này?',
      timestamp: new Date()
    }
  ]);
  const [knowledgeBase, setKnowledgeBase] = useState<KnowledgeItem[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isLoadingStorage, setIsLoadingStorage] = useState(true);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    const loadStoredData = async () => {
      try {
        const stored = await getFullKnowledge();
        setKnowledgeBase(stored);
      } catch (err) {
        console.error("Lỗi tải kho kiến thức:", err);
      } finally {
        setIsLoadingStorage(false);
      }
    };
    loadStoredData();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const userMsg: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput('');
    setIsStreaming(true);

    let assistantMsgContent = '';
    const assistantMsg: Message = {
      role: 'model',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMsg]);

    try {
      const stream = sendMessageStream(newMessages, knowledgeBase);
      for await (const chunk of stream) {
        assistantMsgContent += chunk;
        setMessages(prev => {
          const last = prev[prev.length - 1];
          return [...prev.slice(0, -1), { ...last, content: assistantMsgContent }];
        });
      }
    } catch (err) {
      console.error(err);
      setMessages(prev => {
        const last = prev[prev.length - 1];
        return [...prev.slice(0, -1), { ...last, content: "Có lỗi xảy ra trong quá trình xử lý. Vui lòng thử lại." }];
      });
    } finally {
      setIsStreaming(false);
    }
  };

  const addKnowledge = async (item: KnowledgeItem) => {
    setKnowledgeBase(prev => [...prev, item]);
    await saveKnowledge(item);
  };

  const deleteKnowledge = async (id: string) => {
    setKnowledgeBase(prev => prev.filter(item => item.id !== id));
    await removeKnowledge(id);
  };

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden">
      <aside className="hidden md:block w-80 lg:w-96 flex-shrink-0 z-20">
        <KnowledgeManager 
          onAdd={addKnowledge} 
          knowledgeBase={knowledgeBase} 
          onDelete={deleteKnowledge} 
        />
      </aside>

      <main className="flex-1 flex flex-col min-w-0 bg-white shadow-inner relative">
        <header className="bg-white/90 backdrop-blur-md border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-red-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-red-200 rotate-3">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 18.657A8 8 0 016.343 7.343S7 9 9 10c0-2 .5-5 2.986-7C14 5 16.09 5.777 17.656 7.343A7.99 7.99 0 0120 13a7.98 7.98 0 01-2.343 5.657z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.879 16.121A3 3 0 1012.015 11L11 14H9c0 .768.293 1.536.879 2.121z" />
              </svg>
            </div>
            <div>
              <h1 className="font-bold text-gray-800 text-lg uppercase tracking-tight">Trợ lý PCCC Phú Thọ</h1>
              <p className="text-[10px] text-gray-500 flex items-center gap-1 font-medium">
                <span className={`flex h-2 w-2 rounded-full ${isLoadingStorage ? 'bg-yellow-500 animate-pulse' : 'bg-green-500'}`}></span> 
                HỆ THỐNG SẴN SÀNG • {SYSTEM_DOCUMENTS.length} NGUỒN CHÍNH
              </p>
            </div>
          </div>
          <div className="hidden sm:flex flex-col items-end">
             <span className="text-[10px] font-bold text-red-600 tracking-wider">CỔNG TƯ VẤN PHÁP LUẬT</span>
             <span className="text-[9px] text-gray-400">Trực tuyến 24/7</span>
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 bg-slate-50">
          <div className="max-w-3xl mx-auto space-y-6">
            {messages.map((msg, idx) => (
              <div 
                key={idx} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[85%] md:max-w-[80%] rounded-2xl p-5 shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-tr-none' 
                    : 'bg-white border border-gray-100 text-gray-800 rounded-tl-none'
                }`}>
                  <div className="prose prose-sm max-w-none whitespace-pre-wrap leading-relaxed">
                    {msg.content || (isStreaming && idx === messages.length - 1 ? (
                      <div className="flex items-center space-x-2 py-2">
                         <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce"></div>
                         <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                         <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                      </div>
                    ) : null)}
                  </div>
                  <div className={`mt-3 text-[9px] font-medium uppercase tracking-widest opacity-50 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {msg.role === 'user' ? 'CÔNG DÂN' : 'HỆ THỐNG'}
                  </div>
                </div>
              </div>
            ))}
            <div ref={chatEndRef} />
          </div>
        </section>

        <footer className="p-6 border-t border-gray-100 bg-white">
          <div className="max-w-3xl mx-auto">
            <div className={`relative flex items-end gap-3 bg-gray-50 border border-gray-200 rounded-2xl p-3 focus-within:ring-2 focus-within:ring-red-500/20 focus-within:border-red-500 transition-all ${isStreaming ? 'opacity-70' : ''}`}>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
                placeholder="Nhập nội dung cần tư vấn về PCCC..."
                rows={1}
                className="flex-1 resize-none border-none focus:ring-0 text-sm md:text-base p-2 bg-transparent max-h-48 scrollbar-hide"
                style={{ height: 'auto' }}
              />
              <button
                onClick={handleSend}
