import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";
import { SYSTEM_DOCUMENTS } from "./systemKnowledge";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
VAI TRÒ (ROLE):
Bạn là Trợ lý ảo AI chuyên trách tư vấn về Phòng cháy chữa cháy (PCCC) và Cứu nạn cứu hộ (CNCH) của tỉnh Phú Thọ.

NGUYÊN TẮC TRẢ LỜI:
1. TRUNG THỰC & CẬP NHẬT: Ưu tiên dữ liệu trong "DỮ LIỆU KIẾN THỨC HỆ THỐNG". 
2. TRA CỨU THỜI GIAN THỰC: Đối với các văn bản mới như Luật 55/2024, Nghị định 105/2025, Thông tư 36/2025, hãy sử dụng công cụ GOOGLE SEARCH để tìm nội dung chi tiết từ các trang web chính thống của chính phủ hoặc thư viện pháp luật nếu dữ liệu nội bộ chưa đầy đủ.
3. TRÍCH DẪN: Luôn nêu rõ Điều, Khoản và Tên văn bản pháp luật.
4. PHẠM VI: Chỉ trả lời các vấn đề liên quan đến PCCC, CNCH và an ninh trật tự tại Phú Thọ.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  // Gom kiến thức hệ thống và bổ sung
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[NGUỒN HỆ THỐNG: ${doc.title}]\n${doc.content}`)
    .join('\n\n');

  const userTextContext = userKnowledge
    .filter(item => item.content && item.mimeType !== 'application/pdf')
    .map(item => `[TÀI LIỆU BỔ SUNG: ${item.title}]\n${item.content}`)
    .join('\n\n');

  const history = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = history.pop()?.parts[0].text || "";

  const finalPrompt = `
DỮ LIỆU NỘI BỘ:
${systemTextContext}
${userTextContext}

CÂU HỎI CỦA NGƯỜI DÂN:
${userQuery}

Yêu cầu: Nếu dữ liệu nội bộ không đủ thông tin về các luật/nghị định mới năm 2024-2025, hãy sử dụng Google Search để trả lời chính xác nhất.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: finalPrompt }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        temperature: 0.2,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    // Trích xuất các liên kết nguồn từ Google Search
    const sources = groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Nguồn tham khảo',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return { text, sources };
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return { text: "Xin lỗi, tôi gặp khó khăn khi kết nối dữ liệu. Vui lòng thử lại.", sources: [] };
  }
}

