import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";
import { SYSTEM_DOCUMENTS } from "./systemKnowledge";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

NGUỒN DỮ LIỆU CỐT LÕI:
Bạn sẽ nhận được các tài liệu PDF và văn bản do người dùng (cán bộ/người dân) cung cấp. 
Nhiệm vụ quan trọng nhất là giải đáp dựa trên CHÍNH XÁC nội dung trong các file PDF này.

QUY TẮC PHÂN TÍCH PDF:
1. Đọc kỹ từng trang, chú ý đến các bảng biểu, thông số kỹ thuật và sơ đồ nếu có.
2. Nếu người dân hỏi về quy trình, hãy liệt kê từng bước theo đúng tài liệu.
3. Nếu tài liệu bạn nhận được mâu thuẫn với kiến thức cũ, hãy ưu tiên TÀI LIỆU MỚI NHẤT được gửi kèm.

TRẢ LỜI:
- Luôn trích dẫn: "Dựa trên tài liệu [Tên file]..."
- Ngôn ngữ chuyên nghiệp, hỗ trợ tối đa cho người dân.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  // 1. Chuẩn bị các phần (parts) cho Gemini
  const parts: any[] = [];

  // Thêm hướng dẫn hệ thống và ngữ cảnh văn bản
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[HỆ THỐNG]: ${doc.title}\n${doc.content}`)
    .join('\n\n');

  parts.push({ text: `KIẾN THỨC HỆ THỐNG:\n${systemTextContext}` });

  // 2. Đính kèm các file PDF gốc (Multimodal) từ 3 file bạn gửi
  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: 'application/pdf'
        }
      });
      parts.push({ text: `Nội dung trên là dữ liệu gốc của file: ${item.title}` });
    } else if (item.content) {
      parts.push({ text: `[TÀI LIỆU BỔ SUNG: ${item.title}]:\n${item.content}` });
    }
  });

  // 3. Xây dựng lịch sử chat
  const chatHistory = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = chatHistory[chatHistory.length - 1]?.parts[0].text || "";

  // 4. Gọi API với công cụ tìm kiếm và dữ liệu PDF
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { role: 'user', parts: [...parts, { text: `CÂU HỎI CỦA TÔI: ${userQuery}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

    const sources = groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Nguồn bổ trợ',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return { text, sources };
  } catch (error: any) {
    console.error("Lỗi phân tích tài liệu:", error);
    return { 
      text: "Tôi gặp lỗi khi đang đọc hiểu các file PDF bạn gửi. Bạn vui lòng kiểm tra lại file hoặc thử đặt câu hỏi ngắn hơn nhé.", 
      sources: [] 
    };
  }
}

import React, { useState } from 'react';
import { KnowledgeItem } from '../types';
import { SYSTEM_DOCUMENTS } from '../services/systemKnowledge';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState('');

  const processFile = async (file: File) => {
    if (file.size === 0) return;
    setIsUploading(true);
    setUploadProgress('Đang đọc file...');

    try {
      const fileNameLower = file.name.toLowerCase();

      if (fileNameLower.endsWith('.pdf')) {
        // Chuyển đổi sang Base64 để gửi trực tiếp cho AI (Multimodal)
        const base64 = await new Promise<string>((resolve) => {
          const r = new FileReader();
          r.onload = () => resolve((r.result as string).split(',')[1]);
          r.readAsDataURL(file);
        });

        onAdd({ 
          id: Math.random().toString(36).substr(2, 9), 
          title: file.name, 
          content: '', 
          fileData: base64, 
          mimeType: 'application/pdf', 
          size: file.size 
        });
      } else if (fileNameLower.endsWith('.docx')) {
        const arrayBuffer = await file.arrayBuffer();
        // @ts-ignore
        const result = await window.mammoth.extractRawText({ arrayBuffer });
        onAdd({ 
          id: Math.random().toString(36).substr(2, 9), 
          title: file.name, 
          content: result.value, 
          mimeType: 'text/plain', 
          size: file.size 
        });
      }
    } catch (error) {
      console.error(error);
      alert("Lỗi khi nạp tài liệu.");
    } finally {
      setIsUploading(false);
      setUploadProgress('');
    }
  };

  const formatSize = (bytes: number) => {
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white overflow-hidden shadow-2xl">
      <div className="p-6 bg-gradient-to-br from-red-600 to-red-800">
        <h2 className="font-black flex items-center gap-3 text-lg uppercase tracking-tighter">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
          </svg>
          Trung tâm Dữ liệu
        </h2>
        <p className="text-[10px] text-red-100 font-bold mt-2 uppercase tracking-[0.2em] opacity-80">Nạp 3 file PDF của bạn tại đây</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6 scrollbar-hide">
        <div className="space-y-4">
           <label className={`relative group flex flex-col items-center justify-center p-8 rounded-2xl border-2 border-dashed transition-all cursor-pointer ${
            isUploading ? 'bg-slate-800 border-slate-700 animate-pulse' : 'bg-slate-800/50 border-slate-700 hover:border-red-500 hover:bg-slate-800'
          }`}>
            <input type="file" className="hidden" accept=".pdf,.docx" onChange={(e) => e.target.files?.[0] && processFile(e.target.files[0])} disabled={isUploading} />
            <div className="text-center">
              {isUploading ? (
                <span className="text-xs font-bold text-red-400">{uploadProgress}</span>
              ) : (
                <>
                  <div className="w-12 h-12 bg-red-600/20 text-red-500 rounded-full flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                    </svg>
                  </div>
                  <span className="text-sm font-bold block">Tải 3 file PDF lên</span>
                  <span className="text-[10px] text-slate-500 mt-1 block">Hỗ trợ PDF & Word (Max 100MB)</span>
                </>
              )}
            </div>
          </label>

          <div className="space-y-2">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-2">Danh sách tài liệu đã nạp</h3>
            {knowledgeBase.length === 0 && (
              <div className="text-center py-8 text-slate-600 italic text-xs">Chưa có file nào được nạp.</div>
            )}
            {knowledgeBase.map(item => (
              <div key={item.id} className="group flex items-center gap-3 bg-slate-800/80 p-3 rounded-xl border border-slate-700 hover:border-red-500/50 transition-all">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 ${item.mimeType === 'application/pdf' ? 'bg-red-900/40 text-red-400' : 'bg-blue-900/40 text-blue-400'}`}>
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                </div>
                <div className="min-w-0 flex-1">
                  <p className="text-xs font-bold truncate pr-4">{item.title}</p>
                  <p className="text-[10px] text-slate-500 font-medium">{formatSize(item.size)} • Sẵn sàng phân tích</p>
                </div>
                <button onClick={() => onDelete(item.id)} className="p-2 text-slate-600 hover:text-red-500 transition-colors">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="p-6 bg-slate-950/50 border-t border-slate-800">
         <div className="bg-red-600/10 border border-red-900/30 rounded-lg p-3">
            <p className="text-[10px] text-red-400 font-bold uppercase tracking-tight leading-relaxed">
              LƯU Ý: AI sẽ ưu tiên phân tích 3 file PDF bạn vừa nạp để trả lời câu hỏi của người dân.
            </p>
         </div>
      </div>
    </div>
  );
};

