import React, { useState, useRef, useEffect } from 'react';
import { Message, KnowledgeItem } from './types';
import { sendMessageWithSearch } from './services/geminiService';
import KnowledgeManager from './components/KnowledgeManager';
import { getFullKnowledge, saveKnowledge, removeKnowledge } from './services/storageService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: 'Chào mừng bạn đến với **Hệ thống Trợ lý ảo PCCC Phú Thọ**. 🛡️\n\nTôi đã được nạp đầy đủ các văn bản pháp quy mới nhất và sẵn sàng hỗ trợ bạn giải đáp các thủ tục, quy định về an toàn cháy nổ.\n\nBạn cần tôi tư vấn vấn đề gì?',
      timestamp: new Date()
    }
  ]);
  const [knowledgeBase, setKnowledgeBase] = useState<KnowledgeItem[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    const loadStoredData = async () => {
      const stored = await getFullKnowledge();
      setKnowledgeBase(stored);

      // Nếu đã có dữ liệu nạp sẵn, AI sẽ chào khách theo cách khác
      if (stored.length > 0) {
        setMessages([{
          role: 'model',
          content: `Hệ thống đã sẵn sàng với **${stored.length} tài liệu chuyên sâu** về PCCC được nạp sẵn. 📚\n\nTôi có thể giúp bạn tra cứu nhanh các quy định, định mức kỹ thuật hoặc hướng dẫn thủ tục hành chính. Bạn muốn hỏi gì?`,
          timestamp: new Date()
        }]);
      }
    };
    loadStoredData();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const userMsg: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsStreaming(true);

    try {
      const response = await sendMessageWithSearch([...messages, userMsg], knowledgeBase);

      const assistantMsg: Message = {
        role: 'model',
        content: response.text,
        sources: response.sources,
        timestamp: new Date()
      };

      setMessages(prev => [...prev, assistantMsg]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, {
        role: 'model',
        content: "Xin lỗi, tôi gặp chút gián đoạn khi kết nối dữ liệu. Vui lòng thử lại sau giây lát.",
        timestamp: new Date()
      }]);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className="flex h-screen bg-[#f8fafc] overflow-hidden font-sans selection:bg-red-100 selection:text-red-900">
      {/* Sidebar - Trung tâm nạp dữ liệu (Ẩn mặc định cho người dân) */}
      <div className={`fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:relative lg:translate-x-0 transition-all duration-500 ease-in-out z-50 w-80 lg:w-[380px] flex-shrink-0 shadow-2xl border-r border-slate-200`}>
        <KnowledgeManager 
          onAdd={(item) => {
            setKnowledgeBase(prev => [...prev, item]);
            saveKnowledge(item);
          }} 
          knowledgeBase={knowledgeBase} 
          onDelete={(id) => {
            setKnowledgeBase(prev => prev.filter(i => i.id !== id));
            removeKnowledge(id);
          }} 
        />
        <button 
          onClick={() => setIsSidebarOpen(false)}
          className="lg:hidden absolute top-4 -right-12 bg-slate-900 text-white p-3 rounded-r-xl shadow-xl hover:bg-red-600 transition-colors"
        >
