import { sendMessageWithSearch } from './services/geminiService';
import KnowledgeManager from './components/KnowledgeManager';
import { getFullKnowledge, saveKnowledge, removeKnowledge } from './services/storageService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: 'Chào mừng bạn đến với **Hệ thống Trợ lý ảo PCCC Phú Thọ**. 🛡️\n\nTôi đã được nạp đầy đủ các văn bản pháp quy mới nhất và sẵn sàng hỗ trợ bạn giải đáp các thủ tục, quy định về an toàn cháy nổ.\n\nBạn cần tôi tư vấn vấn đề gì?',
      timestamp: new Date()
    }
  ]);
  const [knowledgeBase, setKnowledgeBase] = useState<KnowledgeItem[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false); // Trạng thái ẩn/hiện công cụ nạp file
  const [logoClickCount, setLogoClickCount] = useState(0); // Đếm số lần nhấp logo để mở Admin
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    const loadStoredData = async () => {
      const stored = await getFullKnowledge();
      setKnowledgeBase(stored);

      if (stored.length > 0) {
        setMessages([{
          role: 'model',
          content: `Hệ thống đã sẵn sàng với **${stored.length} tài liệu chuyên sâu** về PCCC được nạp sẵn. 📚\n\nTôi có thể giúp bạn tra cứu nhanh các quy định, định mức kỹ thuật hoặc hướng dẫn thủ tục hành chính. Bạn muốn hỏi gì?`,
          timestamp: new Date()
        }]);
      }
    };
    loadStoredData();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Cơ chế "Mật lệnh": Nhấp 5 lần vào logo để mở chế độ Admin
  const handleLogoClick = () => {
    const newCount = logoClickCount + 1;
    if (newCount >= 5) {
      const pwd = prompt("Nhập mật mã quản trị để mở vùng nạp dữ liệu:");
      if (pwd === "adminPCCC") { // Bạn có thể thay đổi mật mã này
        setIsAdminMode(true);
        setIsSidebarOpen(true);
        alert("Đã mở chế độ Quản trị viên.");
      } else {
        alert("Mật mã không chính xác.");
      }
      setLogoClickCount(0);
    } else {
      setLogoClickCount(newCount);
      // Reset đếm sau 2 giây nếu không bấm tiếp
      setTimeout(() => setLogoClickCount(0), 2000);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const userMsg: Message = {
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsStreaming(true);

    try {
      const response = await sendMessageWithSearch([...messages, userMsg], knowledgeBase);

      const assistantMsg: Message = {
        role: 'model',
        content: response.text,
        sources: response.sources,
        timestamp: new Date()
      };

      setMessages(prev => [...prev, assistantMsg]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, {
        role: 'model',
        content: "Xin lỗi, tôi gặp chút gián đoạn khi kết nối dữ liệu. Vui lòng thử lại sau giây lát.",
        timestamp: new Date()
      }]);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
