  const handleLogoClick = (e: React.MouseEvent) => {
    // Ngăn chặn các sự kiện lồng nhau
    e.stopPropagation();

    // Tăng số lần nhấn
    clickCountRef.current += 1;
    setVisualClickCount(clickCountRef.current);

    // Reset timer
    if (timerRef.current) clearTimeout(timerRef.current);

    if (clickCountRef.current >= 5) {
      const currentCount = clickCountRef.current;
      clickCountRef.current = 0;
      setVisualClickCount(0);

      // Trì hoãn một chút để hiệu ứng nhấn kết thúc
      setTimeout(() => {
        const pwd = prompt("XÁC NHẬN QUYỀN QUẢN TRỊ\nNhập mật mã để mở vùng nạp dữ liệu PDF:");
