                <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-2 border-white rounded-full"></div>
              </div>

              <div className="hidden sm:block">
                <h1 className={`font-black text-slate-800 text-lg md:text-xl tracking-tight leading-none transition-colors ${visualClickCount > 0 ? 'text-red-600' : ''}`}>AI PCCC PHÚ THỌ</h1>
                <p className="text-[10px] md:text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest flex items-center gap-1.5">
                  <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
