                  msg.role === 'user' 
                    ? 'bg-slate-900 border-slate-800 text-white rounded-tr-none shadow-xl shadow-slate-200' 
                    : 'bg-white border-slate-200 text-slate-800 rounded-tl-none ring-1 ring-slate-100'
