                            <span className="max-w-[200px] truncate">{source.title}</span>
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                  <div className={`mt-5 text-[9px] font-black uppercase tracking-[0.2em] text-slate-400 ${msg.role === 'user' ? 'text-right' : ''}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} • {msg.role === 'user' ? 'Người dân' : 'Trợ lý ảo'}
                  </div>
                </div>
              </div>
            ))}
            {isStreaming && (
              <div className="flex justify-start animate-fadeIn">
                <div className="bg-white border border-slate-200 rounded-[2rem] rounded-tl-none p-8 shadow-sm ring-1 ring-slate-100">
                  <div className="flex items-center space-x-4">
                    <div className="flex space-x-1.5">
                      <div className="w-2 h-2 bg-red-600 rounded-full animate-bounce"></div>
                      <div className="w-2 h-2 bg-red-600 rounded-full animate-bounce [animation-delay:-.3s]"></div>
                      <div className="w-2 h-2 bg-red-600 rounded-full animate-bounce [animation-delay:-.5s]"></div>
                    </div>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Đang đối soát quy định...</span>
                  </div>
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>
        </section>

        <footer className="p-6 md:p-10 bg-white/80 backdrop-blur-md border-t border-slate-100">
          <div className="max-w-4xl mx-auto">
            <div className={`relative flex items-center gap-4 bg-white border-2 border-slate-200 rounded-[2.5rem] p-2.5 pl-8 focus-within:border-red-600/40 focus-within:ring-8 focus-within:ring-red-50/50 shadow-2xl shadow-slate-200/50 transition-all ${isStreaming ? 'opacity-50 pointer-events-none' : ''}`}>
              <textarea
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
                placeholder="Câu hỏi của bạn về quy định PCCC..."
                rows={1}
                className="flex-1 resize-none border-none focus:ring-0 text-sm md:text-[16px] py-4 bg-transparent max-h-40 font-medium placeholder:text-slate-400"
              />
              <button
                onClick={handleSend}
                disabled={!input.trim() || isStreaming}
                className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                  !input.trim() || isStreaming 
                    ? 'bg-slate-100 text-slate-300' 
                    : 'bg-red-600 text-white hover:bg-red-700 hover:scale-105 active:scale-95 shadow-lg shadow-red-200'
                }`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7 rotate-45" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
                </svg>
              </button>
            </div>
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

