import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";
import { SYSTEM_DOCUMENTS } from "./systemKnowledge";

// Fix: Strictly follow initialization guidelines: Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

NGUỒN DỮ LIỆU CỐT LÕI:
Bạn sẽ nhận được các tài liệu PDF và văn bản do người dùng cung cấp. Giải đáp chính xác dựa trên nội dung đó.

QUY TẮC QUAN TRỌNG VỀ BIỂU MẪU:
Nếu người dân hỏi về LINK TẢI, FILE TẢI hoặc CÁCH TẢI các BIỂU MẪU (như đơn đề nghị, giấy chứng nhận, phương án PCCC...), bạn KHÔNG ĐƯỢC tự ý cung cấp link ngoài.
=> HÃY HƯỚNG DẪN: "Vui lòng quay lại trang chủ, truy cập vào phần 'VĂN BẢN' trên Trang thông tin điện tử để tìm kiếm và tải các biểu mẫu chuẩn mới nhất theo quy định."

QUY TẮC PHÂN TÍCH PDF:
1. Trích dẫn chính xác điều khoản, tên file tài liệu.
2. Ưu tiên tài liệu mới nhất được nạp vào hệ thống.
3. Ngôn ngữ chuyên nghiệp, rõ ràng, lễ phép với người dân.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  const parts: any[] = [];
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[HỆ THỐNG]: ${doc.title}\n${doc.content}`)
    .join('\n\n');

  parts.push({ text: `KIẾN THỨC HỆ THỐNG:\n${systemTextContext}` });

  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: 'application/pdf'
        }
      });
      parts.push({ text: `Dữ liệu file: ${item.title}` });
    } else if (item.content) {
      parts.push({ text: `[TÀI LIỆU: ${item.title}]:\n${item.content}` });
    }
  });

  const chatHistory = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = chatHistory[chatHistory.length - 1]?.parts[0].text || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { role: 'user', parts: [...parts, { text: `CÂU HỎI: ${userQuery}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Nguồn bổ trợ',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return { text, sources };
  } catch (error: any) {
    console.error("Lỗi:", error);
    return { 
      text: "Tôi gặp gián đoạn khi đọc tài liệu. Vui lòng thử lại câu hỏi khác hoặc kiểm tra lại file PDF.", 
      sources: [] 
    };
  }
}

