import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";
import { SYSTEM_DOCUMENTS } from "./systemKnowledge";

// Khởi tạo Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

NGUỒN DỮ LIỆU:
Bạn sẽ nhận được một thư viện các tài liệu (PDF, Word, Văn bản). Hãy tổng hợp và trả lời chính xác dựa trên toàn bộ dữ liệu này.

QUY TẮC QUAN TRỌNG VỀ BIỂU MẪU & LINK TẢI:
- Khi người dân hỏi về: link tải, mẫu đơn, biểu mẫu, tờ khai, file mẫu, tải ở đâu...
- TUYỆT ĐỐI KHÔNG tự cung cấp link trực tiếp hoặc file.
- HÃY TRẢ LỜI CỐ ĐỊNH: "Để đảm bảo sử dụng đúng mẫu biểu mới nhất theo quy định hiện hành, vui lòng quay lại trang chủ, truy cập vào mục 'VĂN BẢN' trên Trang thông tin điện tử PCCC Phú Thọ để tìm kiếm và tải về."

QUY TẮC PHẢN HỒI:
1. Nếu có nhiều tài liệu cùng nói về một vấn đề, hãy tổng hợp thông tin từ tài liệu có ngày ban hành mới nhất.
2. Trích dẫn rõ Điều, Khoản và tên văn bản quy phạm pháp luật.
3. Nếu thông tin không có trong dữ liệu được cung cấp, hãy hướng dẫn người dân liên hệ trực tiếp với cơ quan PCCC gần nhất để được hướng dẫn cụ thể.
4. Ngôn ngữ: Lễ phép, chuyên nghiệp, chính xác.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  const parts: any[] = [];

  // Nạp kiến thức hệ thống cố định
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[HỆ THỐNG]: ${doc.title}\n${doc.content}`)
    .join('\n\n');
  parts.push({ text: `KIẾN THỨC NỀN TẢNG:\n${systemTextContext}` });

  // Nạp toàn bộ kho kiến thức người dùng đã tải lên
  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: 'application/pdf'
        }
      });
      parts.push({ text: `Nội dung từ tài liệu: ${item.title}` });
    } else if (item.content) {
      parts.push({ text: `[TÀI LIỆU: ${item.title}]:\n${item.content}` });
    }
  });

  const chatHistory = messages.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = chatHistory[chatHistory.length - 1]?.parts[0].text || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { role: 'user', parts: [...parts, { text: `CÂU HỎI HIỆN TẠI: ${userQuery}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Tham khảo Web',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return { text, sources };
  } catch (error: any) {
    console.error("Lỗi Gemini:", error);
    return { 
      text: "Xin lỗi, hệ thống đang gặp khó khăn khi truy xuất kho dữ liệu văn bản. Vui lòng thử lại sau giây lát.", 
      sources: [] 
    };
  }
}

import React, { useState } from 'react';
import { KnowledgeItem } from '../types';

interface KnowledgeManagerProps {
  onAdd: (item: KnowledgeItem) => void;
  knowledgeBase: KnowledgeItem[];
  onDelete: (id: string) => void;
}

const KnowledgeManager: React.FC<KnowledgeManagerProps> = ({ onAdd, knowledgeBase, onDelete }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  const processFile = async (file: File) => {
    if (file.size === 0) return;
    setIsUploading(true);
    setUploadProgress('Đang xử lý...');

    try {
      const fileNameLower = file.name.toLowerCase();

      if (fileNameLower.endsWith('.pdf')) {
        const base64 = await new Promise<string>((resolve) => {
          const r = new FileReader();
          r.onload = () => resolve((r.result as string).split(',')[1]);
          r.readAsDataURL(file);
        });

        onAdd({ 
          id: Math.random().toString(36).substr(2, 9), 
          title: file.name, 
          content: '', 
          fileData: base64, 
          mimeType: 'application/pdf', 
          size: file.size 
        });
      } else if (fileNameLower.endsWith('.docx')) {
        const arrayBuffer = await file.arrayBuffer();
        // @ts-ignore
        const result = await window.mammoth.extractRawText({ arrayBuffer });
        onAdd({ 
          id: Math.random().toString(36).substr(2, 9), 
          title: file.name, 
          content: result.value, 
          mimeType: 'text/plain', 
          size: file.size 
        });
      }
    } catch (error) {
      console.error(error);
      alert("Lỗi khi nạp tài liệu.");
    } finally {
      setIsUploading(false);
      setUploadProgress('');
    }
  };

  const formatSize = (bytes: number) => {
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  const filteredKnowledge = knowledgeBase.filter(item => 
    item.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="flex flex-col h-full bg-slate-900 text-white overflow-hidden shadow-2xl">
      <div className="p-6 bg-gradient-to-br from-slate-800 to-slate-900 border-b border-white/5">
        <h2 className="font-black flex items-center gap-3 text-xl uppercase tracking-tighter">
          <div className="p-2 bg-red-600 rounded-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
            </svg>
          </div>
          Thư viện Pháp quy
        </h2>
        <p className="text-[10px] text-slate-400 font-bold mt-3 uppercase tracking-[0.2em]">Quản lý kho dữ liệu chuyên môn</p>
      </div>

      <div className="flex-1 overflow-y-auto p-5 space-y-6 scrollbar-hide">
        {/* Upload Area */}
        <label className={`relative group flex flex-col items-center justify-center p-6 rounded-2xl border-2 border-dashed transition-all cursor-pointer ${
          isUploading ? 'bg-slate-800/50 border-red-500/50 animate-pulse' : 'bg-slate-800/30 border-slate-700 hover:border-red-500 hover:bg-slate-800/50'
        }`}>
          <input type="file" className="hidden" accept=".pdf,.docx" onChange={(e) => e.target.files?.[0] && processFile(e.target.files[0])} disabled={isUploading} />
          <div className="text-center">
            {isUploading ? (
              <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 border-4 border-red-600 border-t-transparent rounded-full animate-spin"></div>
                <span className="text-xs font-bold text-red-400 uppercase tracking-widest">{uploadProgress}</span>
              </div>
            ) : (
              <>
                <div className="w-10 h-10 bg-slate-700 text-slate-300 rounded-xl flex items-center justify-center mx-auto mb-3 group-hover:bg-red-600 group-hover:text-white transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <span className="text-sm font-bold block">Thêm tài liệu mới</span>
                <span className="text-[10px] text-slate-500 mt-1 block font-medium">PDF hoặc Word (Không giới hạn số lượng)</span>
