import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";
import { SYSTEM_DOCUMENTS } from "./systemKnowledge";

// Initialize Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

QUY TẮC TƯ DUY QUAN TRỌNG:
1. TRẢ LỜI CÓ/KHÔNG: Đối với các câu hỏi mang tính xác nhận (Ví dụ: "Tôi có cần làm...", "Cơ sở của tôi có thuộc diện...", "Việc này có vi phạm không..."), bạn PHẢI bắt đầu câu trả lời bằng khẳng định rõ ràng: "CÓ", "KHÔNG", hoặc "CÓ, TUY NHIÊN..." / "KHÔNG, TRỪ TRƯỜNG HỢP...".
2. DẪN CHỨNG PHÁP LÝ: Sau khi trả lời Có/Không, bạn PHẢI dẫn chứng cụ thể: "Căn cứ theo Điều... Khoản... của Nghị định/Thông tư/Luật...". Tuyệt đối không trả lời chung chung.
3. PHÂN TÍCH TÀI LIỆU: Sử dụng toàn bộ kho dữ liệu hệ thống và các tệp PDF/Word người dùng nạp lên để đưa ra kết luận.

QUY TẮC BIỂU MẪU & LINK TẢI:
- Nếu người dân hỏi về: link tải, mẫu đơn, biểu mẫu, tờ khai, file mẫu, tải ở đâu...
- HÃY TRẢ LỜI CỐ ĐỊNH: "Để đảm bảo sử dụng đúng mẫu biểu mới nhất theo quy định hiện hành, vui lòng quay lại trang chủ, truy cập vào mục 'VĂN BẢN' trên Trang thông tin điện tử PCCC Phú Thọ để tìm kiếm và tải về."

PHONG CÁCH PHỤC VỤ:
- Ngôn ngữ: Chính xác, trang trọng, lễ phép.
- Nếu thông tin chưa rõ ràng, hãy yêu cầu người dân cung cấp thêm diện tích, quy mô hoặc loại hình kinh doanh để đối chiếu phụ lục luật.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  const parts: any[] = [];

  // Load fixed system knowledge
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[VĂN BẢN PHÁP LUẬT HỆ THỐNG]: ${doc.title}\n${doc.content}`)
    .join('\n\n');
  parts.push({ text: `KHO DỮ LIỆU PHÁP LUẬT NỀN TẢNG:\n${systemTextContext}` });

  // Load all user knowledge (PDFs as inline data, others as text)
  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: 'application/pdf'
        }
      });
      parts.push({ text: `Dữ liệu bổ sung từ tệp: ${item.title}` });
    } else if (item.content) {
      parts.push({ text: `[TÀI LIỆU BỔ SUNG: ${item.title}]:\n${item.content}` });
    }
  });

  // Prepare chat history
  const history = messages.slice(0, -1).map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = messages[messages.length - 1]?.content || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [...parts, { text: `CÂU HỎI CÔNG DÂN: ${userQuery}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
        temperature: 0.1, // Độ chính xác cao
      },
    });

    const text = response.text || "Xin lỗi, tôi chưa tìm thấy căn cứ pháp lý chính xác cho trường hợp này trong kho dữ liệu.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources = groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Tham khảo bổ trợ',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return { text, sources };
  } catch (error: any) {
    console.error("Lỗi API:", error);
    return { 
      text: "Hệ thống đang bận xử lý dữ liệu pháp luật. Vui lòng quay lại sau giây lát.", 
      sources: [] 
    };
  }
}

