export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  const parts: any[] = [];

  // Nạp kho luật hệ thống
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[NGUỒN HỆ THỐNG - ${doc.title}]:\n${doc.content}`)
    .join('\n\n');
  parts.push({ text: `DỮ LIỆU PHÁP LUẬT GỐC:\n${systemTextContext}` });

  // Nạp kho tài liệu người dùng tải lên
  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
