    }
  });

  // Lịch sử trò chuyện
  const history = messages.slice(0, -1).map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = messages[messages.length - 1]?.content || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [...parts, { text: `CÂU HỎI CỦA DÂN: ${userQuery}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        // Loại bỏ googleSearch để đảm bảo AI chỉ tập trung vào tài liệu được up lên
        temperature: 0.1, // Giảm tối đa sự sáng tạo để tăng độ chính xác
      },
    });

    const text = response.text || "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!";

    return { text, sources: [] }; // Không dùng nguồn ngoài web để đảm bảo tính nội bộ
  } catch (error: any) {
    console.error("Lỗi Gemini:", error);
    return { 
      text: "Hiện tại hệ thống đang cập nhật dữ liệu pháp luật. Vui lòng liên hệ cán bộ quản lý PCCC để được hỗ trợ trực tiếp.", 
      sources: [] 
    };
  }
}

import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";
import { SYSTEM_DOCUMENTS } from "./systemKnowledge";

// Khởi tạo Gemini API
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

QUY TẮC CỐT LÕI (TUÂN THỦ TUYỆT ĐỐI):
1. NGUỒN TRI THỨC DUY NHẤT: Bạn chỉ được phép sử dụng thông tin từ các [VĂN BẢN PHÁP LUẬT HỆ THỐNG] và [DỮ LIỆU BỔ SUNG TỪ TỆP] được cung cấp trong ngữ cảnh này. Tuyệt đối không sử dụng kiến thức bên ngoài hoặc thông tin từ internet.
2. CÂU TRẢ LỜI KHI THIẾU THÔNG TIN: Nếu câu hỏi của người dùng không thể được giải đáp thỏa đáng dựa trên các văn bản được cung cấp, bạn PHẢI trả lời nguyên văn câu sau: "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!"
3. QUY TẮC CÓ/KHÔNG: Khi người dùng hỏi các câu hỏi xác nhận (Ví dụ: "Có phải...", "Tôi có cần..."), bạn phải SUY NGHĨ THẬT KỸ dựa trên các điều khoản luật, sau đó khẳng định rõ ràng là "CÓ" hoặc "KHÔNG" ngay đầu câu trả lời.
4. DẪN CHỨNG PHÁP LÝ: Mọi câu trả lời phải đi kèm dẫn chứng cụ thể: "Căn cứ theo Điều... Khoản... của [Tên văn bản]".

QUY TẮC VỀ BIỂU MẪU:
- Nếu hỏi về link tải/mẫu đơn/tờ khai: "Để đảm bảo sử dụng đúng mẫu biểu mới nhất theo quy định hiện hành, vui lòng quay lại trang chủ, truy cập vào mục 'VĂN BẢN' trên Trang thông tin điện tử PCCC Phú Thọ để tìm kiếm và tải về."

PHONG CÁCH LÀM VIỆC:
- Ngôn ngữ: Chính xác, trang trọng, lễ phép. 
- Không trả lời phỏng đoán. Nếu luật không ghi rõ, hãy sử dụng câu trả lời ở mục 2.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  const parts: any[] = [];

  // 1. Nạp kho luật hệ thống (Cố định)
  const systemTextContext = SYSTEM_DOCUMENTS
    .map(doc => `[VĂN BẢN PHÁP LUẬT HỆ THỐNG - ${doc.title}]:\n${doc.content}`)
    .join('\n\n');
  parts.push({ text: `KHO DỮ LIỆU PHÁP LUẬT GỐC:\n${systemTextContext}` });

  // 2. Nạp kho tài liệu người dùng (Admin) tải lên
  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: 'application/pdf'
        }
      });
      parts.push({ text: `[DỮ LIỆU BỔ SUNG TỪ TỆP PDF: ${item.title}]` });
    } else if (item.content) {
      parts.push({ text: `[DỮ LIỆU BỔ SUNG TỪ VĂN BẢN: ${item.title}]:\n${item.content}` });
    }
  });

  // 3. Chuẩn bị lịch sử trò chuyện (không bao gồm tin nhắn cuối cùng)
  const history = messages.slice(0, -1).map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  // 4. Tin nhắn hiện tại của người dùng
  const userQuery = messages[messages.length - 1]?.content || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { 
          role: 'user', 
          parts: [...parts, { text: `CÂU HỎI CÔNG DÂN CẦN GIẢI ĐÁP: ${userQuery}` }] 
        }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Thiết lập độ nhiễu thấp nhất để AI không tự sáng tạo
        topP: 0.1,
        topK: 1
      },
    });

    const text = response.text || "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!";

    // Vì chỉ dùng tài liệu nội bộ, chúng ta không cần hiển thị nguồn ngoài (Google Search)
    return { text, sources: [] }; 
  } catch (error: any) {
    console.error("Lỗi Gemini API:", error);
    return { 
      text: "Hiện tại hệ thống đang cập nhật dữ liệu pháp luật. Vui lòng liên hệ cán bộ quản lý PCCC để được hỗ trợ trực tiếp.", 
      sources: [] 
    };
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { Message, KnowledgeItem } from './types';
import { sendMessageWithSearch } from './services/geminiService';
import KnowledgeManager from './components/KnowledgeManager';
import { getFullKnowledge, saveKnowledge, removeKnowledge } from './services/storageService';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'model',
      content: 'Chào mừng bạn đến với **Hệ thống Trợ lý ảo PCCC Phú Thọ**. 🛡️\n\nTôi đã được nạp đầy đủ các văn bản pháp quy mới nhất và sẵn sàng hỗ trợ bạn giải đáp các thủ tục, quy định về an toàn cháy nổ.\n\nBạn cần tôi tư vấn vấn đề gì?',
      timestamp: new Date()
    }
  ]);
  const [knowledgeBase, setKnowledgeBase] = useState<KnowledgeItem[]>([]);
  const [input, setInput] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isAdminMode, setIsAdminMode] = useState(false);

  const [showPasswordOverlay, setShowPasswordOverlay] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [visualClickCount, setVisualClickCount] = useState(0);
  const clickCountRef = useRef(0);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Kiểm tra nếu đang ở chế độ nhúng (URL có ?embed=true)
  const isEmbedded = new URLSearchParams(window.location.search).get('embed') === 'true';

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    const loadStoredData = async () => {
      try {
        const stored = await getFullKnowledge();
        setKnowledgeBase(stored);
        if (stored.length > 0) {
          setMessages([{
            role: 'model',
            content: `Hệ thống đã sẵn sàng với **${stored.length} tài liệu chuyên sâu** về PCCC được nạp sẵn. 📚\n\nBạn muốn tra cứu quy định hay thủ tục nào?`,
            timestamp: new Date()
          }]);
        }
      } catch (e) {
        console.error("Storage load error:", e);
      }
    };
    loadStoredData();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, isStreaming]);

  const handleLogoClick = (e: React.MouseEvent) => {
    if (isEmbedded) return; // Không cho phép mở admin ở chế độ nhúng trừ khi cần thiết
    e.stopPropagation();
    clickCountRef.current += 1;
    setVisualClickCount(clickCountRef.current);

    if (timerRef.current) clearTimeout(timerRef.current);

    if (clickCountRef.current >= 5) {
      clickCountRef.current = 0;
      setVisualClickCount(0);
      setShowPasswordOverlay(true);
    } else {
      timerRef.current = setTimeout(() => {
        clickCountRef.current = 0;
        setVisualClickCount(0);
      }, 4000);
    }
  };

  const verifyAdmin = () => {
    if (adminPassword === "adminPCCC") {
      setIsAdminMode(true);
      setIsSidebarOpen(true);
      setShowPasswordOverlay(false);
      setAdminPassword('');
    } else {
      alert("Mật mã không chính xác!");
      setAdminPassword('');
    }
  };

  const copyEmbedCode = () => {
    const currentUrl = window.location.href.split('?')[0];
    const embedCode = `<iframe src="${currentUrl}?embed=true" width="100%" height="700px" frameborder="0" style="border:1px solid #e2e8f0; border-radius:12px;"></iframe>`;
    navigator.clipboard.writeText(embedCode);
    alert("Đã sao chép mã nhúng vào bộ nhớ tạm!");
  };

  const handleSend = async () => {
    if (!input.trim() || isStreaming) return;

    const currentInput = input;
    const userMsg: Message = {
      role: 'user',
      content: currentInput,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsStreaming(true);

    try {
      const result = await sendMessageWithSearch([...messages, userMsg], knowledgeBase);
      setMessages(prev => [...prev, {
        role: 'model',
        content: result.text,
        sources: result.sources,
        timestamp: new Date()
      }]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, {
        role: 'model',
        content: "Xin lỗi, tôi gặp chút gián đoạn. Vui lòng thử lại sau.",
        timestamp: new Date()
      }]);
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <div className={`flex h-screen overflow-hidden font-sans relative ${isEmbedded ? 'bg-white' : 'bg-[#f8fafc]'}`}>

      {showPasswordOverlay && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/60 backdrop-blur-md p-4">
          <div className="bg-white rounded-[2rem] p-8 w-full max-w-sm shadow-2xl border border-slate-100 animate-fadeIn">
            <div className="text-center mb-8">
              <div className="w-20 h-20 bg-red-50 text-red-600 rounded-3xl flex items-center justify-center mx-auto mb-4 rotate-3 shadow-inner">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8-0v4h8z" />
                </svg>
              </div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">Cổng Quản Trị</h2>
              <p className="text-sm text-slate-500 mt-2 font-medium">Nhập mật mã để tiếp tục</p>
            </div>

            <input 
              autoFocus
              type="password"
              value={adminPassword}
              onChange={(e) => setAdminPassword(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && verifyAdmin()}
              className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-red-500 focus:ring-4 focus:ring-red-50 outline-none transition-all text-center text-xl font-bold tracking-[0.5em] placeholder:text-slate-300 placeholder:tracking-normal"
              placeholder="Mật mã"
            />

            <div className="flex gap-4 mt-8">
              <button 
                onClick={() => { setShowPasswordOverlay(false); setAdminPassword(''); }}
                className="flex-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-bold transition-all active:scale-95"
              >
                Hủy bỏ
              </button>
              <button 
                onClick={verifyAdmin}
                className="flex-1 py-4 bg-red-600 hover:bg-red-700 text-white rounded-2xl font-bold shadow-xl shadow-red-200 transition-all active:scale-95"
              >
                Xác nhận
              </button>
            </div>
          </div>
        </div>
      )}

      {isAdminMode && (
        <div className={`fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} lg:relative lg:translate-x-0 transition-all duration-500 ease-in-out z-[100] w-80 lg:w-[400px] flex-shrink-0 shadow-2xl border-r border-slate-200`}>
          <div className="h-full flex flex-col">
            <KnowledgeManager 
              onAdd={(item) => {
                setKnowledgeBase(prev => [...prev, item]);
                saveKnowledge(item);
              }} 
              knowledgeBase={knowledgeBase} 
              onDelete={(id) => {
                setKnowledgeBase(prev => prev.filter(i => i.id !== id));
                removeKnowledge(id);
              }} 
            />
            <div className="p-4 bg-slate-900 border-t border-slate-800 space-y-3">
              <button 
                onClick={copyEmbedCode}
                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-xs uppercase tracking-widest transition-all shadow-lg flex items-center justify-center gap-2"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                </svg>
                Lấy mã nhúng Iframe
              </button>
              <button 
                onClick={() => { setIsAdminMode(false); setIsSidebarOpen(false); }}
                className="w-full py-3 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold text-xs uppercase tracking-widest transition-all shadow-lg"
              >
                Đóng Quản trị
              </button>
            </div>
          </div>
        </div>
      )}

      <main className={`flex-1 flex flex-col min-w-0 bg-white relative ${isEmbedded ? 'h-full' : ''}`}>
        {!isEmbedded && (
          <header className="bg-white/95 backdrop-blur-md border-b border-slate-100 px-6 py-4 flex items-center justify-between sticky top-0 z-40">
            <div className="flex items-center gap-5">
              <div 
                className="flex items-center gap-4 cursor-pointer select-none group relative p-1 rounded-2xl active:scale-95 transition-transform" 
                onClick={handleLogoClick}
              >
                <div className="relative">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-lg transition-all duration-200 ${
                    visualClickCount > 0 
                      ? 'bg-red-500 scale-110 ring-4 ring-red-100' 
                      : 'bg-gradient-to-tr from-red-600 to-orange-500 ring-4 ring-red-50'
                  }`}>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-7 w-7" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 18.657A8 8 0 016.343 7.343S7 9 9 10c0-2 .5-5 2.986-7C14 5 16.09 5.777 17.656 7.343A7.99 7.99 0 0120 13a7.98 7.98 0 01-2.343 5.657z" />
                    </svg>
                  </div>
                  {visualClickCount >= 3 && (
                    <div className="absolute -top-6 left-0 text-[10px] font-black text-red-600 animate-bounce uppercase whitespace-nowrap">
                      Admin? ({visualClickCount}/5)
                    </div>
                  )}
                </div>
                <div className="hidden sm:block">
                  <h1 className="font-black text-slate-800 text-lg md:text-xl tracking-tight leading-none">AI PCCC PHÚ THỌ</h1>
                  <p className="text-[10px] md:text-xs font-bold text-slate-400 mt-1 uppercase tracking-widest flex items-center gap-1.5">
                    <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
                    Hệ thống trực tuyến
                  </p>
                </div>
              </div>
            </div>

            <div className="flex items-center gap-4">
              {isAdminMode && (
                <div className="hidden md:block px-4 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest shadow-md">
                  Chế độ quản trị
                </div>
