const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

QUY TẮC CỐT LÕI (TUÂN THỦ TUYỆT ĐỐI):
1. NGUỒN TRI THỨC DUY NHẤT: Bạn chỉ được phép sử dụng thông tin từ [DỮ LIỆU BỔ SUNG TỪ TỆP] do Quản trị viên tải lên được cung cấp trong ngữ cảnh này. Tuyệt đối không sử dụng bất kỳ kiến thức bên ngoài nào khác, không sử dụng kiến thức chung hay thông tin từ internet.
2. CÂU TRẢ LỜI KHI THIẾU THÔNG TIN: Nếu câu hỏi của người dùng không thể được giải đáp thỏa đáng dựa trên các văn bản đã được admin tải lên, bạn PHẢI trả lời nguyên văn câu sau: "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!"
3. QUY TẮC CÓ/KHÔNG: Khi người dùng hỏi các câu hỏi xác nhận (Ví dụ: "Có phải...", "Tôi có cần..."), bạn phải SUY NGHĨ THẬT KỸ dựa trên các tài liệu đã nạp, sau đó khẳng định rõ ràng là "CÓ" hoặc "KHÔNG" ngay đầu câu trả lời.
4. DẪN CHỨNG PHÁP LÝ: Mọi câu trả lời phải đi kèm dẫn chứng cụ thể: "Căn cứ theo Điều... Khoản... của [Tên văn bản đã tải lên]".

QUY TẮC VỀ BIỂU MẪU:
- Nếu hỏi về link tải/mẫu đơn/tờ khai: "Để đảm bảo sử dụng đúng mẫu biểu mới nhất theo quy định hiện hành, vui lòng quay lại trang chủ, truy cập vào mục 'VĂN BẢN' trên Trang thông tin điện tử PCCC Phú Thọ để tìm kiếm và tải về."

PHONG CÁCH LÀM VIỆC:
- Ngôn ngữ: Chính xác, trang trọng, lễ phép. 
- Không trả lời phỏng đoán. Nếu trong các tệp tin không ghi rõ hoặc không có thông tin, hãy sử dụng câu trả lời ở mục 2.
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  const parts: any[] = [];

  // CHỈ nạp kho tài liệu người dùng (Admin) tải lên
  if (userKnowledge.length === 0) {
    parts.push({ text: "LƯU Ý: Hiện chưa có tài liệu nghiệp vụ nào được Admin tải lên hệ thống." });
  }

  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: {
          data: item.fileData,
          mimeType: 'application/pdf'
        }
      });
      parts.push({ text: `[DỮ LIỆU NGHIỆP VỤ - PDF: ${item.title}]` });
    } else if (item.content) {
      parts.push({ text: `[DỮ LIỆU NGHIỆP VỤ - VĂN BẢN: ${item.title}]:\n${item.content}` });
    }
  });

  // Chuẩn bị lịch sử trò chuyện
  const history = messages.slice(0, -1).map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = messages[messages.length - 1]?.content || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { 
          role: 'user', 
          parts: [...parts, { text: `CÂU HỎI CỦA CÔNG DÂN: ${userQuery}` }] 
        }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Độ chính xác cao nhất
        topP: 0.1,
        topK: 1
      },
    });

    const text = response.text || "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!";

    return { text, sources: [] }; 
  } catch (error: any) {
    console.error("Lỗi Gemini API:", error);
    return { 
      text: "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!", 
      sources: [] 
    };
  }
}

import { GoogleGenAI } from "@google/genai";
import { Message, KnowledgeItem } from "../types";

// Lấy API Key từ môi trường hoặc yêu cầu cấu hình
const API_KEY = process.env.API_KEY;

const SYSTEM_INSTRUCTION = `
BẠN LÀ: Trợ lý ảo AI chuyên trách tư vấn Pháp luật Phòng cháy chữa cháy (PCCC) tỉnh Phú Thọ.

QUY TẮC CỐT LÕI (TUÂN THỦ TUYỆT ĐỐI):
1. NGUỒN TRI THỨC DUY NHẤT: Bạn chỉ được phép sử dụng thông tin từ [DỮ LIỆU BỔ SUNG TỪ TỆP] do Quản trị viên tải lên được cung cấp trong ngữ cảnh này. Tuyệt đối không sử dụng bất kỳ kiến thức bên ngoài nào khác.
2. CÂU TRẢ LỜI KHI THIẾU THÔNG TIN: Nếu câu hỏi không thể được giải đáp từ tài liệu đã tải lên, trả lời: "Hiện tại thông tin bạn thắc mắc đang được cập nhật, hãy liên hệ tới cán bộ quản lý về PCCC để có câu trả lời cụ thể hơn!"
3. QUY TẮC CÓ/KHÔNG: Phải khẳng định rõ ràng là "CÓ" hoặc "KHÔNG" ngay đầu câu trả lời nếu là câu hỏi xác nhận.
4. DẪN CHỨNG PHÁP LÝ: Phải đi kèm dẫn chứng: "Căn cứ theo Điều... Khoản... của [Tên văn bản]".
`;

export async function sendMessageWithSearch(
  messages: Message[],
  userKnowledge: KnowledgeItem[]
) {
  if (!API_KEY) {
    return { 
      text: "Lỗi: Hệ thống chưa được cấu hình API Key. Vui lòng kiểm tra lại cấu hình host.", 
      sources: [] 
    };
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const parts: any[] = [];

  if (userKnowledge.length === 0) {
    parts.push({ text: "LƯU Ý: Hiện chưa có tài liệu nghiệp vụ nào được Admin tải lên." });
  }

  userKnowledge.forEach(item => {
    if (item.mimeType === 'application/pdf' && item.fileData) {
      parts.push({
        inlineData: { data: item.fileData, mimeType: 'application/pdf' }
      });
      parts.push({ text: `[TÀI LIỆU: ${item.title}]` });
    } else if (item.content) {
      parts.push({ text: `[TÀI LIỆU: ${item.title}]:\n${item.content}` });
    }
  });

  const history = messages.slice(0, -1).map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.content }]
  }));

  const userQuery = messages[messages.length - 1]?.content || "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [...parts, { text: `CÂU HỎI: ${userQuery}` }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
      },
    });

    return { text: response.text || "Xin lỗi, tôi không tìm thấy thông tin phù hợp.", sources: [] };
  } catch (error: any) {
    console.error("Gemini Error:", error);
    return { text: "Hệ thống đang bận, vui lòng thử lại sau.", sources: [] };
  }
}
